// Scaffold generated by craftgo. Safe to edit; will not be overwritten.
//
// Boots the runtime server with sensible dev-mode defaults:
//   - OpenTelemetry tracer (so trace_id / span_id flow into structured
//     logs out of the box and `traceparent` lands on every response);
//   - OpenTelemetry meter with a Prometheus reader on a dedicated
//     admin listener at :9090/metrics — `otelhttp.HTTPMiddleware`
//     records the standard `http.server.*` instruments, so
//     Prometheus / Grafana Agent / Vector scrape the wire-standard
//     text exposition without any custom code;
//   - every design-declared middleware field wired to its scaffolded
//     constructor;
//   - umbrella routes.RegisterAll for every service.
//
// Replace the placeholder middleware constructor arguments with real
// values before running in production. The legacy `server.RequestID()`
// middleware is intentionally left out — OTel's W3C tracecontext
// propagator already supplies a per-request identifier (`trace_id`)
// that flows into log lines via `WithContext`. Add
// `srv.Use(server.RequestID())` back if you need the dedicated
// `X-Request-Id` header for systems that don't speak W3C trace
// context.

package main

import (
	"context"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/dropship-dev/craftgo/pkg/metrics"
	"github.com/dropship-dev/craftgo/pkg/otel"
	"github.com/dropship-dev/craftgo/pkg/server"

	"github.com/dropship-dev/craftgo/example/internal/middleware"
	"github.com/dropship-dev/craftgo/example/internal/routes"
	"github.com/dropship-dev/craftgo/example/svccontext"
)

func main() {
	// otel.InitDefault wires an in-process TracerProvider with no
	// exporter — spans get valid IDs but go nowhere, which is exactly
	// what you want for `go run` sessions where the only observability
	// signal you need is trace_id / span_id flowing into the logs.
	// Production replaces this with otel.Init() + your own configured
	// TracerProvider so spans actually ship to your collector.
	otel.InitDefault()

	// metrics.InitDefault wires an OTel MeterProvider whose reader is
	// a Prometheus exporter, plus the standard Go runtime / process
	// collectors (so `go_*` and `process_*` series appear alongside
	// `http.server.*`). otelhttp's HTTPMiddleware records the HTTP
	// instruments against this provider automatically — no separate
	// per-request middleware is needed.
	//
	// Switch to OTLP PUSH (gRPC) by replacing the InitDefault call
	// with an explicit Init that wires the appropriate readers:
	//
	//   ctx := context.Background()
	//   provider, err := metrics.Init(
	//       metrics.WithOTLPgRPCReader(ctx, "otel-collector.observability:4317"),
	//   )
	//
	// Or run BOTH (during a migration window — scrape stays live
	// while the new collector is validated):
	//
	//   metrics.Init(
	//       metrics.WithPrometheusReader(),
	//       metrics.WithOTLPgRPCReader(ctx, "collector:4317"),
	//   )
	//
	// HTTP/protobuf is the [WithOTLPHTTPReader] alternative for
	// firewall-restricted networks where gRPC is blocked.
	metricsProvider, err := metrics.InitDefault()
	if err != nil {
		log.Fatalf("metrics init: %v", err)
	}
	adminSrv, adminErrCh := metrics.StartAdmin(metrics.DefaultAdminAddr)
	go func() {
		if err := <-adminErrCh; err != nil {
			log.Printf("admin metrics listener: %v", err)
		}
	}()

	svc := svccontext.NewServiceContext()

	// Each design-declared middleware lives on the embedded
	// Middlewares struct of ServiceContext. Wire each field once at
	// startup with whatever params your impl needs.
	svc.AuthRequired = middleware.NewAuthRequiredMiddleware()
	svc.BodyLimit = middleware.NewBodyLimitMiddleware()
	svc.CORS = middleware.NewCORSMiddleware()
	svc.Compress = middleware.NewCompressMiddleware()
	svc.RateLimit = middleware.NewRateLimitMiddleware()
	svc.RequestID = middleware.NewRequestIDMiddleware()
	svc.Timeout = middleware.NewTimeoutMiddleware()

	// Build the Server and attach runtime globals via Use. Order
	// matters: OTel opens the span first so AccessLog sees the trace
	// ids on ctx (via `WithContext`), and the same `otelhttp.NewHandler`
	// invocation records `http.server.duration` / `request.size` /
	// `response.size` against the configured MeterProvider — no
	// separate metrics middleware is needed. CORS / additional global
	// middleware belong here too; every Use middleware wraps every
	// request and stays cheap when its package's gate is closed.
	srv := server.New(svc)
	srv.Use(otel.HTTPMiddleware("example"))
	srv.Use(server.AccessLog(srv.Logger()))

	// One call wires every service. The umbrella RegisterAll is
	// generated from the DSL service set on every `craftgo gen`.
	routes.RegisterAll(srv, svc)

	go func() {
		log.Println("listening on :8080 (api), :9090 (admin/metrics)")
		if err := srv.Start(":8080"); err != nil && err != http.ErrServerClosed {
			log.Fatal(err)
		}
	}()

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, syscall.SIGINT, syscall.SIGTERM)
	<-stop

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	_ = srv.Stop(ctx)
	_ = metrics.ShutdownAdmin(ctx, adminSrv)
	// Drain any pending OTLP push batch before exit. No-op for
	// pull-only setups; important for push so the final histogram
	// snapshot reaches the collector.
	_ = metricsProvider.Shutdown(ctx)
}
